/* L'Essence — plantilla oscura con tarjetas de imagen */

.wn-lumiere-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0.75rem 1rem;
  background: var(--wn-bg);
  position: sticky;
  top: 0;
  z-index: 100;
  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
}

.wn-lumiere-menu-btn {
  background: transparent;
  border: none;
  color: var(--wn-text);
  font-size: 1.25rem;
  padding: 0.35rem;
}

.wn-lumiere-brand .wn-lumiere-logo {
  max-height: 36px;
  width: auto;
}

.wn-lumiere-name {
  font-family: 'Playfair Display', Georgia, serif;
  font-size: 1.15rem;
  font-weight: 600;
  color: var(--wn-text);
}

.wn-lumiere-avatar {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  overflow: hidden;
  background: var(--wn-surface);
  display: flex;
  align-items: center;
  justify-content: center;
  border: 2px solid var(--wn-primary);
}

.wn-lumiere-avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.wn-lumiere-avatar span {
  font-weight: 700;
  color: var(--wn-primary);
}

.wn-lumiere-hero {
  min-height: 220px;
  background: var(--wn-surface) center/cover no-repeat;
  position: relative;
  margin: 0 0.75rem;
  border-radius: 16px;
  overflow: hidden;
