input.new_string:
    protected function create(array $data)
    {
        $user = User::create([
            'name' => $data['name'],
            'email' => $data['email'],
            'password' => Hash::make($data['password']),
        ]);

        $businessName = trim($data['business_name'] ?? '');
        if ($businessName !== '') {
            $slug = Str::slug($businessName);
            $duplicateSlugCount = Company::where('slug', 'LIKE', "{$slug}%")->count();
            if ($duplicateSlugCount) {
                $slug .= '-' . ($duplicateSlugCount + 1);
            }

            $company = Company::create([
                'name' => $businessName,
                'slug' => $slug,
                'template' => 'lumiere',
                'menu_type' => 1,
                'enabled' => true,
                'user_id' => $user->id,
            ]);

            Cookie::queue(Cookie::forever('selected_company', $company->id));
        }

        return $user;
    }

    protected function registered(Request $request, $user)
    {
        $company = Company::where('user_id', $user->id)->latest('id')->first();
        if ($company) {
            return redirect()->route('admin.companies.edit', $company);
        }

        return redirect($this->redirectTo);
    }
}

